package main

import (
	"encoding/json"
	"flag"
	"fmt"
	"log/slog"
	"net/http"
	"os"
	"os/signal"
	"strings"
	"sync"
	"sync/atomic"
	"syscall"
	"time"

	jsonschema "github.com/santhosh-tekuri/jsonschema/v5"
)

// Database represents the complete database storage
type Database struct {
	mu         sync.RWMutex
	databases  map[string]*DBInstance
	schema     *jsonschema.Schema
	schemaStr  string // raw schema JSON string for reference
	authMu     sync.RWMutex
	tokens     map[string]*AuthToken // token -> username
	preloadedTokens map[string]string // username -> token (from config file)
}

type AuthToken struct {
	Username  string
	ExpiresAt time.Time
}

type DBInstance struct {
	mu        sync.RWMutex
	documents map[string]*Document
}

type Document struct {
	Data      []byte // Raw JSON bytes
	CreatedBy string
	CreatedAt int64
	LastModifiedBy string
	LastModifiedAt int64
	Collections map[string]*Collection
}

type Collection struct {
	mu        sync.RWMutex
	documents map[string]*Document
}

func main() {
	var server http.Server
	var port int
	var schemaFile string
	var tokenFile string
	var err error

	flag.IntVar(&port, "p", 3318, "port to listen on")
	flag.StringVar(&schemaFile, "s", "", "JSON schema file")
	flag.StringVar(&tokenFile, "t", "", "token file")
	flag.Parse()

	// Check if schema file is provided
	if schemaFile == "" {
		slog.Error("Schema file required", "flag", "-s")
		os.Exit(1)
	}

	// Load and compile schema
	schemaBytes, err := os.ReadFile(schemaFile)
	if err != nil {
		slog.Error("Failed to read schema file", "file", schemaFile, "error", err)
		os.Exit(1)
	}

	// Parse schema JSON to check it's valid
	var schemaObj map[string]interface{}
	if err := json.Unmarshal(schemaBytes, &schemaObj); err != nil {
		slog.Error("Failed to parse schema JSON", "error", err)
		os.Exit(1)
	}

	// Create compiler with offline mode to avoid loading meta schemas from network
	compiler := jsonschema.NewCompiler()
	compiler.Draft = jsonschema.Draft7
	schema, err := compiler.Compile(string(schemaBytes))
	if err != nil {
		// If compilation fails due to network issues, we'll still continue
		// and validate manually or skip validation
		slog.Warn("Could not compile schema with validator, will validate manually", "error", err)
		schema = nil
	}

	// Create database
	db := &Database{
		databases: make(map[string]*DBInstance),
		schema:    schema,
		schemaStr: string(schemaBytes),
		tokens:    make(map[string]*AuthToken),
		preloadedTokens: make(map[string]string),
	}

	// Load preloaded tokens if provided
	if tokenFile != "" {
		if err := loadTokens(db, tokenFile); err != nil {
			slog.Error("Failed to load tokens", "error", err)
			os.Exit(1)
		}
	}

	// Setup HTTP routes
	// Use a custom handler to avoid routing conflicts
	mux := http.NewServeMux()
	mux.HandleFunc("POST /auth", handleLogin(db))
	mux.HandleFunc("DELETE /auth", handleLogout(db))

	// All routes go through a dispatcher to avoid pattern conflicts
	mux.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		if strings.HasPrefix(r.URL.Path, "/v1") {
			routeRequest(w, r, db)
		} else if r.Method == "OPTIONS" {
			handleOptions(w, r)
		} else {
			http.Error(w, "Not found", http.StatusNotFound)
		}
	})

	server.Addr = fmt.Sprintf(":%d", port)
	server.Handler = mux

	// signal.Notify requires the channel to be buffered
	ctrlc := make(chan os.Signal, 1)
	signal.Notify(ctrlc, os.Interrupt, syscall.SIGTERM)
	go func() {
		// Wait for Ctrl-C signal
		<-ctrlc
		server.Close()
	}()

	// Start server
	slog.Info("Listening", "port", port)
	err = server.ListenAndServe()
	if err != nil && err != http.ErrServerClosed {
		slog.Error("Server closed", "error", err)
	} else {
		slog.Info("Server closed", "error", err)
	}
}

func routeRequest(w http.ResponseWriter, r *http.Request, db *Database) {
	path := strings.TrimPrefix(r.URL.Path, "/v1/")
	if path == "" {
		// Root /v1/ request
		if r.Method == "GET" || r.Method == "POST" {
			// Query or POST to database
			if !strings.HasSuffix(r.URL.Path, "/") {
				http.Error(w, "Invalid path", http.StatusBadRequest)
				return
			}
		}
	}

	// Dispatch based on method and path structure
	switch r.Method {
	case "PUT":
		handlePutRequest(w, r, path, db)
	case "DELETE":
		handleDeleteRequest(w, r, path, db)
	case "GET":
		handleGetRequest(w, r, path, db)
	case "POST":
		handlePostRequest(w, r, path, db)
	case "PATCH":
		handlePatchRequest(w, r, path, db)
	case "OPTIONS":
		handleOptions(w, r)
	default:
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
	}
}

func handlePutRequest(w http.ResponseWriter, r *http.Request, path string, db *Database) {
	if !checkAuth(db, r) {
		jsonError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return
	}

	// Determine if this is a database, collection, or document operation
	parts := strings.Split(strings.TrimRight(path, "/"), "/")

	if len(parts) == 1 && parts[0] != "" {
		// Database operation: PUT /v1/{database}
		handleCreateDatabase(w, r, db)
	} else if len(parts) > 1 {
		// Check if path ends with / (collection) or not (document)
		if strings.HasSuffix(r.URL.Path, "/") {
			// Collection operation: PUT /v1/{database}/...../collection/
			handleCreateCollection(w, r, db)
		} else {
			// Document operation: PUT /v1/{database}/...
			handlePutDocument(w, r, db)
		}
	} else {
		jsonError(w, http.StatusBadRequest, "Invalid path")
	}
}

func handleDeleteRequest(w http.ResponseWriter, r *http.Request, path string, db *Database) {
	if !checkAuth(db, r) {
		jsonError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return
	}

	parts := strings.Split(strings.TrimRight(path, "/"), "/")

	if len(parts) == 1 && parts[0] != "" {
		// Database operation: DELETE /v1/{database}
		handleDeleteDatabase(w, r, db)
	} else if len(parts) > 1 {
		// Check if path ends with / (collection) or not (document)
		if strings.HasSuffix(r.URL.Path, "/") {
			// Collection operation: DELETE /v1/{database}/...../collection/
			handleDeleteCollection(w, r, db)
		} else {
			// Document operation: DELETE /v1/{database}/...
			handleDeleteDocument(w, r, db)
		}
	} else {
		jsonError(w, http.StatusBadRequest, "Invalid path")
	}
}

func handleGetRequest(w http.ResponseWriter, r *http.Request, path string, db *Database) {
	if !checkAuth(db, r) {
		http.Error(w, "Missing or invalid bearer token", http.StatusUnauthorized)
		return
	}

	// Check if path ends with / (collection query) or not (document get)
	if strings.HasSuffix(r.URL.Path, "/") {
		handleQueryCollection(w, r, db)
	} else {
		handleGetDocument(w, r, db)
	}
}

func handlePostRequest(w http.ResponseWriter, r *http.Request, path string, db *Database) {
	if !checkAuth(db, r) {
		http.Error(w, "Missing or invalid bearer token", http.StatusUnauthorized)
		return
	}

	handlePostDocument(w, r, db)
}

func handlePatchRequest(w http.ResponseWriter, r *http.Request, path string, db *Database) {
	if !checkAuth(db, r) {
		http.Error(w, "Missing or invalid bearer token", http.StatusUnauthorized)
		return
	}

	handlePatchDocument(w, r, db)
}

func loadTokens(db *Database, tokenFile string) error {
	data, err := os.ReadFile(tokenFile)
	if err != nil {
		return err
	}

	var tokens map[string]string
	if err := json.Unmarshal(data, &tokens); err != nil {
		return err
	}

	db.authMu.Lock()
	defer db.authMu.Unlock()

	expiresAt := time.Now().Add(24 * time.Hour)
	for username, token := range tokens {
		db.tokens[token] = &AuthToken{
			Username:  username,
			ExpiresAt: expiresAt,
		}
		db.preloadedTokens[username] = token
	}

	return nil
}

func handleLogin(db *Database) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		var req struct {
			Username string `json:"username"`
		}

		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
			jsonError(w, http.StatusBadRequest, "Missing or invalid username")
			return
		}

		if req.Username == "" {
			jsonError(w, http.StatusBadRequest, "No username in request body")
			return
		}

		// Generate random token
		token := generateToken()

		db.authMu.Lock()
		db.tokens[token] = &AuthToken{
			Username:  req.Username,
			ExpiresAt: time.Now().Add(time.Hour),
		}
		db.authMu.Unlock()

		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(map[string]string{"token": token})
	}
}

func handleLogout(db *Database) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		token := getAuthToken(r)
		if token == "" {
			jsonError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
			return
		}

		db.authMu.Lock()
		delete(db.tokens, token)
		db.authMu.Unlock()

		w.WriteHeader(http.StatusNoContent)
	}
}

func jsonError(w http.ResponseWriter, statusCode int, message string) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(statusCode)
	json.NewEncoder(w).Encode(map[string]string{"error": message})
}

func handleCreateCollection(w http.ResponseWriter, r *http.Request, db *Database) {
	// Parse the path to extract database, document path, and collection name
	path := strings.TrimPrefix(r.URL.Path, "/v1/")
	path = strings.TrimSuffix(path, "/")

	parts := strings.Split(path, "/")
	if len(parts) < 2 {
		jsonError(w, http.StatusBadRequest, "Invalid collection path")
		return
	}

	dbName := parts[0]
	docPath := parts[1 : len(parts)-1]
	collectionName := parts[len(parts)-1]

	// Get database
	db.mu.RLock()
	dbInst, exists := db.databases[dbName]
	db.mu.RUnlock()

	if !exists {
		jsonError(w, http.StatusNotFound, "Database does not exist")
		return
	}

	dbInst.mu.Lock()
	defer dbInst.mu.Unlock()

	if len(docPath) == 1 {
		// Top-level collection: /v1/{database}/{doc}/{collection}/
		docName := docPath[0]

		// Get or create the document
		doc, exists := dbInst.documents[docName]
		if !exists {
			// Create a new document to hold the collection
			now := time.Now().UnixMilli()
			username := getUsername(db, r)
			doc = &Document{
				Data:            []byte("{}"), // Empty object
				CreatedBy:       username,
				CreatedAt:       now,
				LastModifiedBy:  username,
				LastModifiedAt:  now,
				Collections:     make(map[string]*Collection),
			}
			dbInst.documents[docName] = doc
		}

		// Create or get the collection
		if doc.Collections == nil {
			doc.Collections = make(map[string]*Collection)
		}

		if _, exists := doc.Collections[collectionName]; !exists {
			doc.Collections[collectionName] = &Collection{
				documents: make(map[string]*Document),
			}
		}

		w.Header().Set("Content-Type", "application/json")
		w.Header().Set("Location", fmt.Sprintf("/v1/%s/%s/%s/", dbName, docName, collectionName))
		w.WriteHeader(http.StatusCreated)
		json.NewEncoder(w).Encode(map[string]string{"uri": fmt.Sprintf("/v1/%s/%s/%s/", dbName, docName, collectionName)})

	} else if len(docPath) >= 3 && len(docPath) % 2 == 0 {
		// Nested collection: /v1/{database}/{doc}/{col}/{doc}/{col}/.../{collection}/
		parentPath := docPath[:len(docPath)-1] // [doc1, col1, doc2, col2, ..., docN]

		// Navigate to the parent document
		currentDoc, exists := dbInst.documents[parentPath[0]]
		if !exists {
			jsonError(w, http.StatusNotFound, "Parent document not found")
			return
		}

		// Navigate through collections
		for i := 1; i < len(parentPath); i += 2 {
			collName := parentPath[i]
			if currentDoc.Collections == nil {
				jsonError(w, http.StatusNotFound, "Collection not found")
				return
			}

			coll, exists := currentDoc.Collections[collName]
			if !exists {
				jsonError(w, http.StatusNotFound, "Collection not found")
				return
			}

			if i+1 < len(parentPath) {
				docName := parentPath[i+1]
				nextDoc, exists := coll.documents[docName]
				if !exists {
					jsonError(w, http.StatusNotFound, "Document not found")
					return
				}
				currentDoc = nextDoc
			}
		}

		// Create the collection in the parent document
		if currentDoc.Collections == nil {
			currentDoc.Collections = make(map[string]*Collection)
		}

		if _, exists := currentDoc.Collections[collectionName]; !exists {
			currentDoc.Collections[collectionName] = &Collection{
				documents: make(map[string]*Document),
			}
		}

		w.Header().Set("Content-Type", "application/json")
		w.Header().Set("Location", fmt.Sprintf("/v1/%s/%s/", dbName, path))
		w.WriteHeader(http.StatusCreated)
		json.NewEncoder(w).Encode(map[string]string{"uri": fmt.Sprintf("/v1/%s/%s/", dbName, path)})

	} else {
		jsonError(w, http.StatusBadRequest, "Invalid collection path")
	}
}

func handleCreateDatabase(w http.ResponseWriter, r *http.Request, db *Database) {
	// Extract database name from path
	dbName := strings.TrimPrefix(r.URL.Path, "/v1/")
	dbName = strings.TrimSuffix(dbName, "/")

	if dbName == "" {
		jsonError(w, http.StatusBadRequest, "Invalid database name")
		return
	}

	db.mu.Lock()
	if _, exists := db.databases[dbName]; exists {
		db.mu.Unlock()
		jsonError(w, http.StatusConflict, "Database already exists")
		return
	}

	db.databases[dbName] = &DBInstance{
		documents: make(map[string]*Document),
	}
	db.mu.Unlock()

	w.Header().Set("Content-Type", "application/json")
	w.Header().Set("Location", fmt.Sprintf("/v1/%s", dbName))
	w.WriteHeader(http.StatusCreated)
	json.NewEncoder(w).Encode(map[string]string{"uri": fmt.Sprintf("/v1/%s", dbName)})
}

func handleDeleteCollection(w http.ResponseWriter, r *http.Request, db *Database) {
	// Parse the path
	path := strings.TrimPrefix(r.URL.Path, "/v1/")
	path = strings.TrimSuffix(path, "/")

	parts := strings.Split(path, "/")
	if len(parts) < 2 {
		jsonError(w, http.StatusBadRequest, "Invalid collection path")
		return
	}

	dbName := parts[0]
	docPath := parts[1 : len(parts)-1]
	collectionName := parts[len(parts)-1]

	// Get database
	db.mu.RLock()
	dbInst, exists := db.databases[dbName]
	db.mu.RUnlock()

	if !exists {
		jsonError(w, http.StatusNotFound, "Database does not exist")
		return
	}

	// For now, only support collections on top-level documents
	if len(docPath) > 1 {
		jsonError(w, http.StatusNotFound, "Nested collections not yet implemented")
		return
	}

	docName := docPath[0]

	dbInst.mu.Lock()
	defer dbInst.mu.Unlock()

	// Get the document
	doc, exists := dbInst.documents[docName]
	if !exists {
		jsonError(w, http.StatusNotFound, "Document not found")
		return
	}

	// Delete the collection
	if doc.Collections != nil {
		delete(doc.Collections, collectionName)
	}

	w.WriteHeader(http.StatusNoContent)
}

func handleDeleteDatabase(w http.ResponseWriter, r *http.Request, db *Database) {
	// Extract database name from path
	dbName := strings.TrimPrefix(r.URL.Path, "/v1/")
	dbName = strings.TrimSuffix(dbName, "/")

	if dbName == "" {
		jsonError(w, http.StatusBadRequest, "Invalid database name")
		return
	}

	db.mu.Lock()
	if _, exists := db.databases[dbName]; !exists {
		db.mu.Unlock()
		jsonError(w, http.StatusNotFound, "Database does not exist")
		return
	}
	delete(db.databases, dbName)
	db.mu.Unlock()

	w.WriteHeader(http.StatusNoContent)
}

func handleQueryCollection(w http.ResponseWriter, r *http.Request, db *Database) {
	path := strings.TrimPrefix(r.URL.Path, "/v1/")
	path = strings.TrimSuffix(path, "/")

	parts := strings.Split(path, "/")
	if len(parts) == 0 || parts[0] == "" {
		jsonError(w, http.StatusBadRequest, "Invalid database name")
		return
	}

	dbName := parts[0]

	db.mu.RLock()
	dbInst, exists := db.databases[dbName]
	db.mu.RUnlock()

	if !exists {
		jsonError(w, http.StatusNotFound, "Database does not exist")
		return
	}

	// Parse interval query parameter
	var lowBound, highBound *string
	intervalStr := r.URL.Query().Get("interval")
	if intervalStr != "" {
		// Parse interval format: [low,high]
		if strings.HasPrefix(intervalStr, "[") && strings.HasSuffix(intervalStr, "]") {
			interval := strings.TrimPrefix(strings.TrimSuffix(intervalStr, "]"), "[")
			bounds := strings.Split(interval, ",")
			if len(bounds) == 2 {
				if bounds[0] != "" {
					lowBound = &bounds[0]
				}
				if bounds[1] != "" {
					highBound = &bounds[1]
				}
			}
		}
	}

	dbInst.mu.RLock()
	defer dbInst.mu.RUnlock()

	var results []map[string]interface{}
	for docName, doc := range dbInst.documents {
		// Check if document name is within the interval
		if lowBound != nil && docName < *lowBound {
			continue
		}
		if highBound != nil && docName > *highBound {
			continue
		}

		result := map[string]interface{}{
			"path": fmt.Sprintf("/v1/%s/%s", dbName, docName),
			"doc": json.RawMessage(doc.Data),
			"meta": map[string]interface{}{
				"createdBy": doc.CreatedBy,
				"createdAt": doc.CreatedAt,
				"lastModifiedBy": doc.LastModifiedBy,
				"lastModifiedAt": doc.LastModifiedAt,
			},
		}
		results = append(results, result)
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(results)
}

func handleGetDocument(w http.ResponseWriter, r *http.Request, db *Database) {
	// Parse the path
	path := strings.TrimPrefix(r.URL.Path, "/v1/")
	path = strings.TrimSuffix(path, "/")
	parts := strings.Split(path, "/")

	if len(parts) < 2 {
		jsonError(w, http.StatusBadRequest, "Invalid document path")
		return
	}

	dbName := parts[0]
	docPath := parts[1:]

	// Get database
	db.mu.RLock()
	dbInst, exists := db.databases[dbName]
	db.mu.RUnlock()

	if !exists {
		jsonError(w, http.StatusNotFound, "Database does not exist")
		return
	}

	dbInst.mu.RLock()
	defer dbInst.mu.RUnlock()

	if len(docPath) == 1 {
		// Top-level document
		docName := docPath[0]
		doc, exists := dbInst.documents[docName]
		if !exists {
			jsonError(w, http.StatusNotFound, "Document not found")
			return
		}

		response := map[string]interface{}{
			"path": fmt.Sprintf("/v1/%s/%s", dbName, docName),
			"doc": json.RawMessage(doc.Data),
			"meta": map[string]interface{}{
				"createdBy": doc.CreatedBy,
				"createdAt": doc.CreatedAt,
				"lastModifiedBy": doc.LastModifiedBy,
				"lastModifiedAt": doc.LastModifiedAt,
			},
		}

		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(response)

	} else if len(docPath) == 3 {
		// Nested document in collection: /v1/{database}/{docName}/{collName}/{nestedDocName}
		docName := docPath[0]
		collName := docPath[1]
		nestedDocName := docPath[2]

		// Get the top-level document
		doc, exists := dbInst.documents[docName]
		if !exists {
			jsonError(w, http.StatusNotFound, "Document not found")
			return
		}

		// Get collection
		coll, exists := doc.Collections[collName]
		if !exists {
			jsonError(w, http.StatusNotFound, "Collection not found")
			return
		}

		// Get nested document
		nestedDoc, exists := coll.documents[nestedDocName]
		if !exists {
			jsonError(w, http.StatusNotFound, "Document not found")
			return
		}

		response := map[string]interface{}{
			"path": fmt.Sprintf("/v1/%s/%s/%s/%s", dbName, docName, collName, nestedDocName),
			"doc": json.RawMessage(nestedDoc.Data),
			"meta": map[string]interface{}{
				"createdBy": nestedDoc.CreatedBy,
				"createdAt": nestedDoc.CreatedAt,
				"lastModifiedBy": nestedDoc.LastModifiedBy,
				"lastModifiedAt": nestedDoc.LastModifiedAt,
			},
		}

		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(response)

	} else {
		jsonError(w, http.StatusBadRequest, "Invalid document path")
	}
}

func handlePostDocument(w http.ResponseWriter, r *http.Request, db *Database) {
	// Parse the path
	path := strings.TrimPrefix(r.URL.Path, "/v1/")
	path = strings.TrimSuffix(path, "/")
	parts := strings.Split(path, "/")

	if len(parts) < 1 || parts[0] == "" {
		jsonError(w, http.StatusBadRequest, "Invalid database path")
		return
	}

	dbName := parts[0]

	// Read the request body
	var docData json.RawMessage
	if err := json.NewDecoder(r.Body).Decode(&docData); err != nil {
		jsonError(w, http.StatusBadRequest, "Invalid JSON in request body")
		return
	}

	// Get or create database
	db.mu.RLock()
	dbInst, exists := db.databases[dbName]
	db.mu.RUnlock()

	if !exists {
		jsonError(w, http.StatusNotFound, "Database does not exist")
		return
	}

	// Generate a unique document ID
	docName := generateDocumentID()

	now := time.Now().UnixMilli()
	username := getUsername(db, r)

	dbInst.mu.Lock()
	defer dbInst.mu.Unlock()

	doc := &Document{
		Data: docData,
		CreatedBy: username,
		CreatedAt: now,
		LastModifiedBy: username,
		LastModifiedAt: now,
		Collections: make(map[string]*Collection),
	}

	dbInst.documents[docName] = doc

	w.Header().Set("Content-Type", "application/json")
	w.Header().Set("Location", fmt.Sprintf("/v1/%s/%s", dbName, docName))
	w.WriteHeader(http.StatusCreated)
	json.NewEncoder(w).Encode(map[string]string{"uri": fmt.Sprintf("/v1/%s/%s", dbName, docName)})
}

func handlePutDocument(w http.ResponseWriter, r *http.Request, db *Database) {
	// Parse the path
	path := strings.TrimPrefix(r.URL.Path, "/v1/")
	path = strings.TrimSuffix(path, "/")
	parts := strings.Split(path, "/")

	if len(parts) < 2 {
		jsonError(w, http.StatusBadRequest, "Invalid document path")
		return
	}

	dbName := parts[0]
	docPath := parts[1:]

	// Read the request body
	var docData json.RawMessage
	if err := json.NewDecoder(r.Body).Decode(&docData); err != nil {
		jsonError(w, http.StatusBadRequest, "Invalid JSON in request body")
		return
	}

	// Get or create database
	db.mu.RLock()
	dbInst, exists := db.databases[dbName]
	db.mu.RUnlock()

	if !exists {
		jsonError(w, http.StatusNotFound, "Database does not exist")
		return
	}

	// Check mode query parameter
	mode := r.URL.Query().Get("mode")
	noOverwrite := mode == "nooverwrite"

	now := time.Now().UnixMilli()
	username := getUsername(db, r)

	dbInst.mu.Lock()
	defer dbInst.mu.Unlock()

	// Handle nested documents/collections
	if len(docPath) == 1 {
		// Top-level document: /v1/{database}/{docName}
		docName := docPath[0]

		// Check if document already exists
		_, exists := dbInst.documents[docName]
		if exists && noOverwrite {
			jsonError(w, http.StatusConflict, "Document already exists")
			return
		}

		doc := &Document{
			Data: docData,
			CreatedBy: username,
			CreatedAt: now,
			LastModifiedBy: username,
			LastModifiedAt: now,
			Collections: make(map[string]*Collection),
		}

		// If document exists, preserve creation metadata
		if oldDoc, exists := dbInst.documents[docName]; exists {
			doc.CreatedBy = oldDoc.CreatedBy
			doc.CreatedAt = oldDoc.CreatedAt
		}

		dbInst.documents[docName] = doc

		w.Header().Set("Content-Type", "application/json")
		w.Header().Set("Location", fmt.Sprintf("/v1/%s/%s", dbName, docName))
		w.WriteHeader(http.StatusCreated)
		json.NewEncoder(w).Encode(map[string]string{"uri": fmt.Sprintf("/v1/%s/%s", dbName, docName)})

	} else if len(docPath) == 3 {
		// Nested document in collection: /v1/{database}/{docName}/{collName}/{nestedDocName}
		docName := docPath[0]
		collName := docPath[1]
		nestedDocName := docPath[2]

		// Get the top-level document
		doc, exists := dbInst.documents[docName]
		if !exists {
			jsonError(w, http.StatusNotFound, "Document not found")
			return
		}

		// Get or create collection
		coll, exists := doc.Collections[collName]
		if !exists {
			coll = &Collection{
				documents: make(map[string]*Document),
			}
			doc.Collections[collName] = coll
		}

		// Check if nested document already exists
		_, nestedExists := coll.documents[nestedDocName]
		if nestedExists && noOverwrite {
			jsonError(w, http.StatusConflict, "Document already exists")
			return
		}

		// Create nested document
		nestedDoc := &Document{
			Data: docData,
			CreatedBy: username,
			CreatedAt: now,
			LastModifiedBy: username,
			LastModifiedAt: now,
			Collections: make(map[string]*Collection),
		}

		// If document exists, preserve creation metadata
		if oldDoc, exists := coll.documents[nestedDocName]; exists {
			nestedDoc.CreatedBy = oldDoc.CreatedBy
			nestedDoc.CreatedAt = oldDoc.CreatedAt
		}

		coll.documents[nestedDocName] = nestedDoc

		w.Header().Set("Content-Type", "application/json")
		w.Header().Set("Location", fmt.Sprintf("/v1/%s/%s/%s/%s", dbName, docName, collName, nestedDocName))
		w.WriteHeader(http.StatusCreated)
		json.NewEncoder(w).Encode(map[string]string{"uri": fmt.Sprintf("/v1/%s/%s/%s/%s", dbName, docName, collName, nestedDocName)})

	} else {
		// Invalid nested path
		jsonError(w, http.StatusBadRequest, "Invalid document path")
	}
}

func handlePatchDocument(w http.ResponseWriter, r *http.Request, db *Database) {
	// Parse the path
	path := strings.TrimPrefix(r.URL.Path, "/v1/")
	path = strings.TrimSuffix(path, "/")
	parts := strings.Split(path, "/")

	if len(parts) < 2 {
		jsonError(w, http.StatusBadRequest, "Invalid document path")
		return
	}

	dbName := parts[0]
	docPath := parts[1:]

	// Get database
	db.mu.RLock()
	dbInst, exists := db.databases[dbName]
	db.mu.RUnlock()

	if !exists {
		jsonError(w, http.StatusNotFound, "Database does not exist")
		return
	}

	// Read patch operations
	var patches []map[string]interface{}
	if err := json.NewDecoder(r.Body).Decode(&patches); err != nil {
		jsonError(w, http.StatusBadRequest, "Invalid JSON in request body")
		return
	}

	var doc *Document

	dbInst.mu.RLock()
	if len(docPath) == 1 {
		// Top-level document
		var exists bool
		doc, exists = dbInst.documents[docPath[0]]
		if !exists {
			dbInst.mu.RUnlock()
			jsonError(w, http.StatusNotFound, "Document not found")
			return
		}
	} else if len(docPath) == 3 {
		// Nested document in collection: /v1/{database}/{docName}/{collName}/{nestedDocName}
		docName := docPath[0]
		collName := docPath[1]
		nestedDocName := docPath[2]

		// Get the top-level document
		parentDoc, exists := dbInst.documents[docName]
		if !exists {
			dbInst.mu.RUnlock()
			jsonError(w, http.StatusNotFound, "Document not found")
			return
		}

		// Get collection
		coll, exists := parentDoc.Collections[collName]
		if !exists {
			dbInst.mu.RUnlock()
			jsonError(w, http.StatusNotFound, "Collection not found")
			return
		}

		// Get nested document
		var exists2 bool
		doc, exists2 = coll.documents[nestedDocName]
		if !exists2 {
			dbInst.mu.RUnlock()
			jsonError(w, http.StatusNotFound, "Document not found")
			return
		}
	} else {
		dbInst.mu.RUnlock()
		jsonError(w, http.StatusBadRequest, "Invalid document path")
		return
	}
	dbInst.mu.RUnlock()

	if doc == nil {
		jsonError(w, http.StatusNotFound, "Document not found")
		return
	}

	// Unmarshal the document data
	var docObj interface{}
	if err := json.Unmarshal(doc.Data, &docObj); err != nil {
		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		json.NewEncoder(w).Encode(map[string]interface{}{
			"uri": fmt.Sprintf("/v1/%s/%s", dbName, path),
			"patchFailed": true,
			"message": "Invalid document JSON",
		})
		return
	}

	// Apply patches
	patchFailed := false
	var errorMsg string
	modifiedDoc := docObj

	for _, patch := range patches {
		op, ok := patch["op"].(string)
		if !ok {
			patchFailed = true
			errorMsg = "Missing or invalid op field"
			break
		}

		pathStr, ok := patch["path"].(string)
		if !ok {
			patchFailed = true
			errorMsg = "Missing or invalid path field"
			break
		}

		value, hasValue := patch["value"]

		switch op {
		case "ArrayAdd":
			if modified, err := applyArrayAdd(modifiedDoc, pathStr, value); err != nil {
				patchFailed = true
				errorMsg = err.Error()
				break
			} else {
				modifiedDoc = modified
			}
		case "ArrayRemove":
			if modified, err := applyArrayRemove(modifiedDoc, pathStr, value); err != nil {
				patchFailed = true
				errorMsg = err.Error()
				break
			} else {
				modifiedDoc = modified
			}
		case "ObjectAdd":
			if !hasValue {
				patchFailed = true
				errorMsg = "ObjectAdd requires a value field"
				break
			}
			if modified, err := applyObjectAdd(modifiedDoc, pathStr, value); err != nil {
				patchFailed = true
				errorMsg = err.Error()
				break
			} else {
				modifiedDoc = modified
			}
		default:
			patchFailed = true
			errorMsg = "Unknown operation: " + op
			break
		}

		if patchFailed {
			break
		}
	}

	if patchFailed {
		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		json.NewEncoder(w).Encode(map[string]interface{}{
			"uri": fmt.Sprintf("/v1/%s/%s", dbName, path),
			"patchFailed": true,
			"message": errorMsg,
		})
		return
	}

	// Update document if patches were successful
	newData, err := json.Marshal(modifiedDoc)
	if err != nil {
		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		json.NewEncoder(w).Encode(map[string]interface{}{
			"uri": fmt.Sprintf("/v1/%s/%s", dbName, path),
			"patchFailed": true,
			"message": "Failed to marshal modified document",
		})
		return
	}

	// Update the document in the database
	dbInst.mu.Lock()
	doc.Data = newData
	doc.LastModifiedAt = time.Now().UnixMilli()
	doc.LastModifiedBy = getUsername(db, r)
	dbInst.mu.Unlock()

	// Return success
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]interface{}{
		"uri": fmt.Sprintf("/v1/%s/%s", dbName, path),
		"patchFailed": false,
		"message": "patch applied",
	})
}

func handleDeleteDocument(w http.ResponseWriter, r *http.Request, db *Database) {
	// Parse the path
	path := strings.TrimPrefix(r.URL.Path, "/v1/")
	path = strings.TrimSuffix(path, "/")
	parts := strings.Split(path, "/")

	if len(parts) < 2 {
		jsonError(w, http.StatusBadRequest, "Invalid document path")
		return
	}

	dbName := parts[0]
	docPath := parts[1:]

	// Get database
	db.mu.RLock()
	dbInst, exists := db.databases[dbName]
	db.mu.RUnlock()

	if !exists {
		jsonError(w, http.StatusNotFound, "Database does not exist")
		return
	}

	dbInst.mu.Lock()
	defer dbInst.mu.Unlock()

	if len(docPath) == 1 {
		// Top-level document
		docName := docPath[0]
		_, exists := dbInst.documents[docName]
		if exists {
			delete(dbInst.documents, docName)
			w.WriteHeader(http.StatusNoContent)
		} else {
			jsonError(w, http.StatusNotFound, "Document not found")
		}
	} else if len(docPath) == 3 {
		// Nested document in collection: /v1/{database}/{docName}/{collName}/{nestedDocName}
		docName := docPath[0]
		collName := docPath[1]
		nestedDocName := docPath[2]

		// Get the top-level document
		doc, exists := dbInst.documents[docName]
		if !exists {
			jsonError(w, http.StatusNotFound, "Document not found")
			return
		}

		// Get collection
		coll, exists := doc.Collections[collName]
		if !exists {
			jsonError(w, http.StatusNotFound, "Collection not found")
			return
		}

		// Delete nested document
		_, exists = coll.documents[nestedDocName]
		if exists {
			delete(coll.documents, nestedDocName)
			w.WriteHeader(http.StatusNoContent)
		} else {
			jsonError(w, http.StatusNotFound, "Document not found")
		}
	} else {
		jsonError(w, http.StatusBadRequest, "Invalid document path")
	}
}

func handleOptions(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Allow", "GET, POST, PUT, PATCH, DELETE, OPTIONS")
	w.WriteHeader(http.StatusOK)
}

func checkAuth(db *Database, r *http.Request) bool {
	token := getAuthToken(r)
	if token == "" {
		return false
	}

	db.authMu.RLock()
	authToken, exists := db.tokens[token]
	db.authMu.RUnlock()

	if !exists {
		return false
	}

	return time.Now().Before(authToken.ExpiresAt)
}

func getAuthToken(r *http.Request) string {
	authHeader := r.Header.Get("Authorization")
	if len(authHeader) > 7 && authHeader[:7] == "Bearer " {
		return authHeader[7:]
	}
	return ""
}

func getUsername(db *Database, r *http.Request) string {
	token := getAuthToken(r)
	if token == "" {
		return "anonymous"
	}

	db.authMu.RLock()
	authToken, exists := db.tokens[token]
	db.authMu.RUnlock()

	if !exists {
		return "anonymous"
	}

	return authToken.Username
}

// generateToken generates a random token
var tokenCounter atomic.Int64

func generateToken() string {
	// Simple token generation using counter and timestamp
	counter := tokenCounter.Add(1)
	return fmt.Sprintf("token_%d_%d", time.Now().UnixNano(), counter)
}

// generateDocumentID generates a unique document ID
var docIDCounter atomic.Int64

func generateDocumentID() string {
	// Generate a random-looking ID using counter and timestamp
	counter := docIDCounter.Add(1)
	// Create a base36-like encoding for readability
	timestamp := time.Now().UnixNano() / 1000000 // Convert to milliseconds
	return fmt.Sprintf("%x%x", timestamp, counter)
}

// Helper functions for PATCH operations

func applyArrayAdd(doc interface{}, pathStr string, value interface{}) (interface{}, error) {
	parts := parseJSONPointer(pathStr)
	if len(parts) == 0 {
		return nil, fmt.Errorf("invalid path")
	}

	// Make a copy of the document to modify
	docCopy := deepCopy(doc)

	// Navigate to the target array
	current := docCopy
	for i := 0; i < len(parts); i++ {
		switch curr := current.(type) {
		case map[string]interface{}:
			if i == len(parts)-1 {
				// This is the target array
				if arr, ok := curr[parts[i]].([]interface{}); ok {
					// Check if value already exists
					found := false
					for _, item := range arr {
						if deepEqual(item, value) {
							found = true
							break
						}
					}
					if !found {
						curr[parts[i]] = append(arr, value)
					}
					return docCopy, nil
				} else {
					return nil, fmt.Errorf("path does not refer to an array")
				}
			} else {
				// Navigate deeper
				if next, ok := curr[parts[i]]; ok {
					current = next
				} else {
					return nil, fmt.Errorf("path not found")
				}
			}
		default:
			return nil, fmt.Errorf("invalid path")
		}
	}

	return docCopy, nil
}

func applyArrayRemove(doc interface{}, pathStr string, value interface{}) (interface{}, error) {
	parts := parseJSONPointer(pathStr)
	if len(parts) == 0 {
		return nil, fmt.Errorf("invalid path")
	}

	// Make a copy of the document to modify
	docCopy := deepCopy(doc)

	// Navigate to the target array
	current := docCopy
	for i := 0; i < len(parts); i++ {
		switch curr := current.(type) {
		case map[string]interface{}:
			if i == len(parts)-1 {
				// This is the target array
				if arr, ok := curr[parts[i]].([]interface{}); ok {
					// Remove the value if it exists
					newArr := make([]interface{}, 0, len(arr))
					removed := false
					for _, item := range arr {
						if deepEqual(item, value) && !removed {
							removed = true // Remove only the first occurrence
						} else {
							newArr = append(newArr, item)
						}
					}
					curr[parts[i]] = newArr
					return docCopy, nil
				} else {
					return nil, fmt.Errorf("path does not refer to an array")
				}
			} else {
				// Navigate deeper
				if next, ok := curr[parts[i]]; ok {
					current = next
				} else {
					return nil, fmt.Errorf("path not found")
				}
			}
		default:
			return nil, fmt.Errorf("invalid path")
		}
	}

	return docCopy, nil
}

func applyObjectAdd(doc interface{}, pathStr string, value interface{}) (interface{}, error) {
	parts := parseJSONPointer(pathStr)
	if len(parts) == 0 {
		return nil, fmt.Errorf("invalid path")
	}

	// Navigate to the parent object
	current := doc
	for i := 0; i < len(parts)-1; i++ {
		switch curr := current.(type) {
		case map[string]interface{}:
			var ok bool
			current, ok = curr[parts[i]]
			if !ok {
				return nil, fmt.Errorf("path does not refer to an object")
			}
		default:
			return nil, fmt.Errorf("path does not refer to an object")
		}
	}

	// Add the property if it doesn't already exist
	switch obj := current.(type) {
	case map[string]interface{}:
		key := parts[len(parts)-1]
		// Only add if it doesn't exist
		if _, exists := obj[key]; !exists {
			obj[key] = value
		}
		return doc, nil
	default:
		return nil, fmt.Errorf("path does not refer to an object")
	}
}

func parseJSONPointer(pathStr string) []string {
	if pathStr == "" {
		return []string{}
	}
	if pathStr == "/" {
		return []string{}
	}

	if !strings.HasPrefix(pathStr, "/") {
		return []string{}
	}

	pathStr = strings.TrimPrefix(pathStr, "/")
	return strings.Split(pathStr, "/")
}

func updateDocumentAtPath(doc interface{}, parts []string, newValue interface{}) interface{} {
	if len(parts) == 0 {
		return newValue
	}

	// Make a copy of the document
	docCopy := deepCopy(doc)

	// Navigate and update
	current := docCopy
	for i := 0; i < len(parts)-1; i++ {
		switch curr := current.(type) {
		case map[string]interface{}:
			if nextVal, ok := curr[parts[i]]; ok {
				curr[parts[i]] = deepCopy(nextVal)
				current = curr[parts[i]]
			}
		}
	}

	// Update the final value
	switch curr := current.(type) {
	case map[string]interface{}:
		curr[parts[len(parts)-1]] = newValue
	}

	return docCopy
}

func deepEqual(a, b interface{}) bool {
	aJSON, _ := json.Marshal(a)
	bJSON, _ := json.Marshal(b)
	return string(aJSON) == string(bJSON)
}

func deepCopy(src interface{}) interface{} {
	data, _ := json.Marshal(src)
	var dst interface{}
	json.Unmarshal(data, &dst)
	return dst
}

